	if plan.Changes.Empty() {
		log.Println("[DEBUG] no planned changes, skipping apply graph check")
		return nil
	}
	log.Println("[DEBUG] building apply graph to check for errors")

	_, _, diags := c.applyGraph(plan, config, opts.ApplyOpts(), true)
